async (page) => {
  const asciiMap = await page.evaluate(() => {
    const m = window.__latestAsciiMap;
    return m && !m.error ? (m.ascii + '\n\n' + m.legendText) : JSON.stringify(m);
  });
  // Also check equipment
  const equip = await page.evaluate(() => {
    const p = window.game && window.game.player;
    if (!p) return 'no player';
    return JSON.stringify({
      weaponKey: p.weaponKey || p.weapon,
      equipment: p.equipment
    });
  });
  return 'ASCII:\n' + asciiMap + '\n\nEQUIP:\n' + equip;
}

async (page) => {
