async (page) => {
  // Kill several crabs using entity labels and watch for drops or quest advancement
  for (let i = 0; i < 5; i++) {
    const clicked = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const crab = (gs.nearby_entities || []).find(e => e.name === 'Crab' && e.on_screen && e.click_x);
      if (!crab) return null;
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {
        clientX: crab.click_x, clientY: crab.click_y, bubbles: true, ctrlKey: false
      }));
      return {x: crab.x, y: crab.y};
    });
    if (!clicked) break;
    await page.waitForTimeout(4000);

    // Check for drops/quest advancement
    const check = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const drops = (gs.nearby_entities || []).filter(e => e.type === 4);
      const anvil = gs.quests.find(q => q.key === 'anvilsechoes');
      return {drops, stage: anvil?.stage, hp: gs.player_stats.hp + '/' + gs.player_stats.max_hp};
    });

    if (check.drops.length > 0 || check.stage > 1) {
      // Something happened!
      break;
    }
  }

  const finalState = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const drops = (gs.nearby_entities || []).filter(e => e.type === 4);
    const inv = gs.inventory.filter(i => !['Logs', 'Feather', 'String'].includes(i.name));
    const anvil = gs.quests.find(q => q.key === 'anvilsechoes');
    return {pos: gs.player_position, hp: `${gs.player_stats.hp}/${gs.player_stats.max_hp}`, drops, interestingInv: inv, questStage: anvil?.stage, questSubStage: anvil?.subStage};
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return JSON.stringify(finalState);
}

